final class EquipmentLoadoutResult{private $data;public function __construct(array $data){$this->data=array_merge(['allowed'=>true,'reason'=>null,'reason_code'=>null,'conflicting_slots'=>[],'conflicting_items'=>[],'requires_confirmation'=>false,'required_actions'=>[]],$data);$this->data['conflicting_slots']=array_values($this->data['conflicting_slots']);$this->data['conflicting_items']=array_values($this->data['conflicting_items']);$this->data['required_actions']=array_values($this->data['required_actions']);}public function allowed(){return(bool)$this->data['allowed'];}public function reason(){return$this->data['reason'];}public function reasonCode(){return$this->data['reason_code'];}public function requiresConfirmation(){return(bool)$this->data['requires_confirmation'];}public function conflictingSlots(){return$this->data['conflicting_slots'];}public function toArray(){return$this->data;}}
